 * Trouver le maximum d'un tableau via pointeurs
 * p+i pointe vers le i-ieme element apres p
 * *(p+i) lit la valeur a cette adresse
 * ═══════════════════════════════════════════════ */
int example_max(const int *arr, int n) {
    int max = *arr;  /* premier element = *(arr+0) */
    for (int i = 1; i < n; i++) {
        if (*(arr + i) > max) {  /* arithmetique de pointeurs */
            max = *(arr + i);
        }
    }
    return max;
}
